var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"코치도, 유미나 씨도 갑자기 사라져서 골치 아픈데 이건 또 무슨 날벼락이죠?","JPN":"コーチも、ヤナギさんもいきなり消えて頭痛いのに、これまたどういうことなの？","ENG":"It was troublesome enough that both Coach and Mina disappeared. And now this?","TWN":"教練和劉米娜突然消失就夠讓人頭痛了，這又是什麼情況？"},"stage":{"bg":"CITY_CENTER2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"앞으로 잘 풀릴 일만 남은 줄 알았는데!","JPN":"面倒事はもう片付いたと思ってたのに！","ENG":"I thought there was no way but up!","TWN":"我還以為事情會越來越好！"},"stage":{"bg":"CITY_CENTER2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그러게나 말이다.","JPN":"まったくだな。","ENG":"Tell me about it.","TWN":"就是說啊。"},"stage":{"bg":"CITY_CENTER2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"챔피언 타이틀을 달게 되면 돈방석에서 뒹굴 줄 알았는데, 또 침식체랑 뒹굴게 될 줄은 몰랐네.","JPN":"チャンピオンになったら金持ちになれると思ってたのに、また侵食体と仲良しすることになるなんて。","ENG":"I thought I'd be rolling in dough after becoming the champion. But I never imagined I'd be rolling among C.O.s.","TWN":"我本以為奪得冠軍後一定會一夕暴富呢，沒想到還是和侵蝕體糾纏不清。"},"stage":{"bg":"CITY_CENTER2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"으아아, 침식체가 왜 이렇게 많죠? 이럴 줄 알았으면 어제 운동 적당히 할 걸!","JPN":"うわあ、なんでこんなに沢山いるんですか？　こうなるって知ってたら、昨日の運動は適当に済ませたのに！","ENG":"Ahh, why are there so many C.O.s? I would've exercised less yesterday if I knew this was going to happen!","TWN":"呃啊啊，怎麼會有這麼多侵蝕體？早知道昨天我就不要練得那麼勤快了！"},"stage":{"bg":"CITY_CENTER2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"팔이… 팔이 움직이질 않아요오-!","JPN":"腕が……腕が動きませんよぉ～！","ENG":"My arm... My arm won't moooove!","TWN":"我的手臂……我的手臂舉不起來了！"},"stage":{"bg":"CITY_CENTER2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"너무 부지런해도 탈이라니까. 카운터가 근육통이라니.","JPN":"熱心すぎるのも困りものだな。カウンターが筋肉痛だなんて。","ENG":"Welp, seems like it's possible to be too diligent. I can't believe a Counter has sore muscles.","TWN":"所以說太認真也不好，制裁者竟然會肌肉痠痛。"},"stage":{"bg":"CITY_CENTER2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"노엘한테 스쿼트 천 개부터 시킨 건 라이카였잖아요!","JPN":"ノエルにスクワット1000回やらせたのはライカだったわね！","ENG":"You were the one who made her do a thousand squats, Laika!","TWN":"明明是萊卡叫洛艾兒做一千個深蹲的！"},"stage":{"bg":"CITY_CENTER2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"특훈이 받고 싶다는데 뭐 어쩌겠어. 카운터라고 근육단련법이 따로 있는 것도 아니고.","JPN":"特訓したいと言うんだから仕方ないだろ。カウンターだからって、特別な筋肉の鍛え方があるわけでもないし。","ENG":"She wanted special training. What was I supposed to do? It's not like Counters have a different way of gaining muscle.","TWN":"那是她自己想要接受特訓啊。制裁者又沒有什麼特別的訓練方法。"},"stage":{"bg":"CITY_CENTER2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"아무튼 저희 중 유일한 카운터가 벌써 드러눕게 만들면 어쩌자는 거예요!","JPN":"この中で唯一のカウンターがもうくたばってしまうなんて、この後どうするの！？","ENG":"Whatever the case, what are we supposed to do now that the only Counter among us is already down?!","TWN":"你害我們唯一的制裁者倒了，現在怎麼辦！"},"stage":{"bg":"CITY_CENTER2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"라이카가 책임져요!","JPN":"ライカが責任取ってよね！","ENG":"This is your responsibility, Laika!","TWN":"萊卡要負責！"},"stage":{"bg":"CITY_CENTER2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"어디 보자… 내 책임은 한 200발 정도 남은 것 같거든?","JPN":"どれどれ……私の責任はあと200発くらい残ってるみたいだけど。","ENG":"Let's see... It seems like I have about 200 responsibilities left in my gun.","TWN":"讓我看看……我的責任還剩下大約200發子彈的分量。"},"stage":{"bg":"CITY_CENTER2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"이걸로 어떻게든 주차장까지만 뚫어보자고.","JPN":"これでなんとか駐車場まで乗り切ってみよう。","ENG":"Let's use this to get to the parking lot somehow.","TWN":"我們得用這些在停車場突圍。"},"stage":{"bg":"CITY_CENTER2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"빨리 정규 팀원을 더 충원하던가 해야지, 정말.","JPN":"もう、早く正規のチームメンバーを雇わないと。","ENG":"Ugh, I have to recruit more full-time team members or something.","TWN":"看來得必須儘快補充正式隊員了。"},"stage":{"bg":"CITY_CENTER2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};